import {
  createContext,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from 'react'
import type { Session, UserAttributes, SignInWithPasswordCredentials, SignUpWithPasswordCredentials, AuthError } from '@supabase/supabase-js'
import { supabase } from '../lib/supabase'
import type { UnitWithOrg } from '../types'

interface AuthContextValue {
  session: Session | null
  isSuper: boolean
  adminUnits: UnitWithOrg[]
  loading: boolean
  signIn: (credentials: SignInWithPasswordCredentials) => Promise<{ error: AuthError | null }>
  signUp: (credentials: SignUpWithPasswordCredentials) => Promise<{ error: AuthError | null }>
  signOut: () => Promise<void>
  resetPassword: (email: string) => Promise<{ error: AuthError | null }>
  updatePassword: (attributes: UserAttributes) => Promise<{ error: AuthError | null }>
  refreshPermissions: () => Promise<void>
}

const AuthContext = createContext<AuthContextValue | null>(null)

async function fetchAdminUnits(userId: string): Promise<UnitWithOrg[]> {
  const { data } = await supabase
    .from('unit_admins')
    .select('unit:units(id, org_id, name, description, created_at, organization:organizations(id, name, created_at))')
    .eq('user_id', userId)

  if (!data) return []
  return data.map(row => {
    const unit = row.unit as unknown as UnitWithOrg & { organization: UnitWithOrg['organization'] }
    return {
      ...unit,
      organization: unit.organization,
    }
  })
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [session, setSession] = useState<Session | null>(null)
  const [isSuper, setIsSuper] = useState(false)
  const [adminUnits, setAdminUnits] = useState<UnitWithOrg[]>([])
  const [loading, setLoading] = useState(true)

  async function applySession(session: Session | null) {
    setSession(session)
    if (!session) {
      setIsSuper(false)
      setAdminUnits([])
      return
    }
    const role = session.user.user_metadata?.role as string | undefined
    const super_ = role === 'superadmin'
    setIsSuper(super_)
    if (!super_) {
      const units = await fetchAdminUnits(session.user.id)
      setAdminUnits(units)
    } else {
      setAdminUnits([])
    }
  }

  useEffect(() => {
    supabase.auth.getSession().then(async ({ data: { session } }) => {
      await applySession(session)
      setLoading(false)
    })

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      applySession(session)
    })

    return () => subscription.unsubscribe()
  }, [])

  async function signIn(credentials: SignInWithPasswordCredentials) {
    const { error } = await supabase.auth.signInWithPassword(credentials)
    return { error }
  }

  async function signUp(credentials: SignUpWithPasswordCredentials) {
    const { error } = await supabase.auth.signUp(credentials)
    return { error }
  }

  async function signOut() {
    await supabase.auth.signOut()
  }

  async function resetPassword(email: string) {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/admin/update-password`,
    })
    return { error }
  }

  async function updatePassword(attributes: UserAttributes) {
    const { error } = await supabase.auth.updateUser(attributes)
    return { error }
  }

  async function refreshPermissions() {
    if (!session) return
    const units = await fetchAdminUnits(session.user.id)
    setAdminUnits(units)
  }

  return (
    <AuthContext.Provider value={{ 
      session, 
      isSuper, 
      adminUnits, 
      loading, 
      signIn, 
      signUp, 
      signOut, 
      resetPassword, 
      updatePassword,
      refreshPermissions
    }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error('useAuth must be used within AuthProvider')
  return ctx
}

import { useEffect, useState } from 'react'
import { supabase } from '../lib/supabase'
import type { DashboardMember, Organization, Service, ServiceType, Unit } from '../types'

// Г”Г¶ГҮГ”Г¶ГҮ Organizations Г”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮ

export function useOrganizations() {
  const [orgs, setOrgs] = useState<Organization[]>([])
  const [loading, setLoading] = useState(true)

  async function fetch() {
    const { data } = await supabase.from('organizations').select('*').order('name')
    setOrgs(data ?? [])
    setLoading(false)
  }

  useEffect(() => { fetch() }, [])

  async function createOrg(name: string): Promise<Organization> {
    const { data, error } = await supabase.from('organizations').insert({ name }).select().single()
    if (error) throw error
    setOrgs(prev => [...prev, data].sort((a, b) => a.name.localeCompare(b.name)))
    return data
  }

  async function updateOrg(id: string, name: string): Promise<Organization> {
    const { data, error } = await supabase.from('organizations').update({ name }).eq('id', id).select().single()
    if (error) throw error
    setOrgs(prev => prev.map(o => o.id === id ? data : o).sort((a, b) => a.name.localeCompare(b.name)))
    return data
  }

  async function deleteOrg(id: string) {
    await supabase.from('organizations').delete().eq('id', id)
    setOrgs(prev => prev.filter(o => o.id !== id))
  }

  return { orgs, loading, createOrg, updateOrg, deleteOrg, refetch: fetch }
}

// Г”Г¶ГҮГ”Г¶ГҮ Units Г”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮ

export function useUnits(orgId: string | null) {
  const [units, setUnits] = useState<Unit[]>([])
  const [loading, setLoading] = useState(true)

  async function fetch() {
    if (!orgId) { setUnits([]); setLoading(false); return }
    const { data } = await supabase.from('units').select('*').eq('org_id', orgId).order('name')
    setUnits(data ?? [])
    setLoading(false)
  }

  useEffect(() => { setLoading(true); fetch() }, [orgId])

  async function createUnit(name: string, description?: string): Promise<Unit> {
    if (!orgId) throw new Error('No org selected')
    const { data, error } = await supabase
      .from('units')
      .insert({ org_id: orgId, name, description: description ?? null })
      .select()
      .single()
    if (error) throw error
    setUnits(prev => [...prev, data].sort((a, b) => a.name.localeCompare(b.name)))
    return data
  }

  async function updateUnit(id: string, name: string, description?: string): Promise<Unit> {
    const { data, error } = await supabase
      .from('units')
      .update({ name, description: description ?? null })
      .eq('id', id)
      .select()
      .single()
    if (error) throw error
    setUnits(prev => prev.map(u => u.id === id ? data : u).sort((a, b) => a.name.localeCompare(b.name)))
    return data
  }

  async function deleteUnit(id: string) {
    await supabase.from('units').delete().eq('id', id)
    setUnits(prev => prev.filter(u => u.id !== id))
  }

  return { units, loading, createUnit, updateUnit, deleteUnit, refetch: fetch }
}

// Г”Г¶ГҮГ”Г¶ГҮ Unit Admins Г”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮ

export interface UnitAdmin {
  id: string
  user_id: string
  email: string
  created_at: string
}

export function useUnitAdmins(unitId: string | null) {
  const [admins, setAdmins] = useState<UnitAdmin[]>([])
  const [loading, setLoading] = useState(true)

  async function fetch() {
    if (!unitId) { setAdmins([]); setLoading(false); return }
    const { data } = await supabase
      .from('unit_admins')
      .select('id, user_id, created_at')
      .eq('unit_id', unitId)
    setAdmins(
      (data ?? []).map((r: { id: string; user_id: string; created_at: string }) => ({
        id: r.id,
        user_id: r.user_id,
        email: 'Г”ГҮГ¶',        // email not directly joinable without service role
        created_at: r.created_at,
      })),
    )
    setLoading(false)
  }

  useEffect(() => { setLoading(true); fetch() }, [unitId])

  async function addAdmin(email: string) {
    const { data, error } = await supabase.rpc('add_unit_admin_by_email', {
      p_unit_id: unitId,
      p_email: email,
    })
    if (error) throw error
    const result = data as { success: boolean; error?: string }
    if (!result.success) throw new Error(result.error ?? 'Failed to add admin')
    await fetch()
  }

  async function removeAdmin(id: string) {
    await supabase.from('unit_admins').delete().eq('id', id)
    setAdmins(prev => prev.filter(a => a.id !== id))
  }

  return { admins, loading, addAdmin, removeAdmin }
}

// Г”Г¶ГҮГ”Г¶ГҮ Services Г”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮ

export function useServices(unitId: string | null) {
  const [services, setServices] = useState<Service[]>([])
  const [loading, setLoading] = useState(true)

  async function fetch() {
    if (!unitId) { setServices([]); setLoading(false); return }
    const { data } = await supabase
      .from('services')
      .select('*')
      .eq('unit_id', unitId)
      .order('date', { ascending: false })
    setServices(data ?? [])
    setLoading(false)
  }

  useEffect(() => { setLoading(true); fetch() }, [unitId])

  async function createService(date: string, service_type: ServiceType): Promise<Service> {
    if (!unitId) throw new Error('No unit selected')
    const { data, error } = await supabase
      .from('services')
      .insert({ unit_id: unitId, date, service_type })
      .select()
      .single()
    if (error) throw error
    setServices(prev => [data, ...prev])
    return data
  }

  return { services, loading, createService, refetch: fetch }
}

// Г”Г¶ГҮГ”Г¶ГҮ Dashboard (attendance for a service) Г”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮГ”Г¶ГҮ

export function useAdminDashboard(serviceId: string | null) {
  const [members, setMembers] = useState<DashboardMember[]>([])
  const [loading, setLoading] = useState(true)
  const [loadingMore, setLoadingMore] = useState(false)
  const [page, setPage] = useState(0)
  const [hasMore, setHasMore] = useState(true)
  const [total, setTotal] = useState(0)

  const PAGE_SIZE = 100

  async function fetchCount() {
    if (!serviceId) return
    const { data: service } = await supabase.from('services').select('unit_id').eq('id', serviceId).single()
    if (!service) return
    const { count } = await supabase
      .from('members')
      .select('*', { count: 'exact', head: true })
      .eq('unit_id', service.unit_id)
      .eq('status', 'active')
    setTotal(count ?? 0)
  }

  async function fetchMembers(pageToFetch: number, isNew: boolean = false) {
    if (!serviceId) { setMembers([]); setLoading(false); return }

    if (pageToFetch === 0) {
      setLoading(true)
      fetchCount() // Refresh total count
    } else {
      setLoadingMore(true)
    }

    const { data, error } = await supabase.rpc('get_service_members_full', { 
      p_service_id: serviceId,
      p_limit: PAGE_SIZE,
      p_offset: pageToFetch * PAGE_SIZE
    })

    if (error) {
      console.error('Failed to fetch dashboard members:', error)
      setLoading(false)
      setLoadingMore(false)
      return
    }

    const newMembers = (data ?? []) as DashboardMember[]

    if (isNew) {
      setMembers(newMembers)
      setPage(0)
    } else {
      setMembers(prev => [...prev, ...newMembers])
      setPage(pageToFetch)
    }

    setHasMore(newMembers.length === PAGE_SIZE)
    setLoading(false)
    setLoadingMore(false)
  }

  useEffect(() => { fetchMembers(0, true) }, [serviceId])

  useEffect(() => {
    if (!serviceId) return
    const channel = supabase
      .channel(`attendance-${serviceId}`)
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'attendance', filter: `service_id=eq.${serviceId}` },
        (payload) => {
          const rec = payload.new as { member_id: string; checkin_time: string }
          setMembers(prev =>
            prev.map(m => m.id === rec.member_id ? { ...m, checked_in: true, checkin_time: rec.checkin_time } : m),
          )
        },
      )
      .subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [serviceId])

  const loadMore = () => {
    if (!loadingMore && hasMore) {
      fetchMembers(page + 1)
    }
  }

  const present = members.filter(m => m.checked_in)
  const absent = members.filter(m => !m.checked_in)

  return { 
    members, 
    present, 
    absent, 
    total, 
    loading, 
    loadingMore, 
    hasMore, 
    loadMore, 
    refetch: () => fetchMembers(0, true) 
  }
}

import { useState, useEffect } from 'react'
import { supabase } from '../lib/supabase'
import type { MemberNotification } from '../types'

export function useBirthdayNotifications(unitId: string | undefined) {
    const [notifications, setNotifications] = useState<MemberNotification[]>([])
    const [loading, setLoading] = useState(true)

    const fetchNotifications = async () => {
        if (!unitId) return
        const { data, error } = await supabase.rpc('get_pending_notifications', { p_unit_id: unitId })
        if (!error && data) {
            setNotifications(data)
        }
        setLoading(false)
    }

    const dismissNotification = async (id: string) => {
        const { error } = await supabase
            .from('member_notifications')
            .update({ dismissed: true })
            .eq('id', id)

        if (!error) {
            setNotifications(prev => prev.filter(n => n.id !== id))
        }
    }

    useEffect(() => {
        fetchNotifications()

        // Poll every 5 minutes
        const interval = setInterval(fetchNotifications, 5 * 60 * 1000)
        return () => clearInterval(interval)
    }, [unitId])

    return {
        notifications,
        loading,
        dismissNotification,
        count: notifications.length,
        refresh: fetchNotifications,
    }
}

